function ModelMainCity:OnMainCityVillainListResp(pb,ret)
	self._heroRefIdList = {}
	local str
	for i,v in ipairs(pb.refIdList) do
		table.insert(self._heroRefIdList,v)
		if str then
			str = str .. "," .. v
		else
			str = v
		end
	end
	if str then
		printInfoNR("服务端下发的礼物小人列表 ： " .. str)
	end
end

